const items = $input.all();

function get(obj, path, fallback = '') {
  return path.split('.').reduce((acc, key) => {
    if (acc && acc[key] !== undefined && acc[key] !== null) return acc[key];
    return undefined;
  }, obj) ?? fallback;
}

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function sql(value) {
  if (value === null || value === undefined) return 'NULL';

  return `'${String(value)
    .replace(/\\/g, '\\\\')
    .replace(/'/g, "''")}'`;
}

function normalizePhone(body) {
  const leadPhone =
    clean(get(body, 'lead.phone_normalized')) ||
    clean(get(body, 'lead.phone')) ||
    clean(body.whatsapp);

  const digits = leadPhone.replace(/\D/g, '');

  // Evita salvar só "55" como telefone válido
  if (!digits || digits === '55' || digits.length < 10) return '';

  if (digits.startsWith('55')) return digits;

  return `55${digits}`;
}

function normalizeDatetime(body) {
  const datetime = clean(body.datetime);

  if (datetime) {
    return datetime.slice(0, 19);
  }

  const createdAt = clean(body.created_at);

  if (createdAt) {
    return createdAt.replace('T', ' ').replace('Z', '').slice(0, 19);
  }

  return '';
}

function normalizeDate(datetime, createdAt) {
  const base = clean(datetime) || clean(createdAt);
  if (!base) return '';

  return base.slice(0, 10);
}

return items.map(item => {
  const body = item.json.body || {};
  const tracking = body.tracking || {};
  const allParams = tracking.all_url_params || {};
  const lead = body.lead || {};
  const answers = body.answers || {};
  const statuses = body.statuses || {};

  const datetime = normalizeDatetime(body);
  const date = normalizeDate(datetime, body.created_at);

  const params = {
    event: clean(body.event),
    lead_source: clean(body.lead_source),
    form_name: clean(body.form_name),
    classification: clean(body.classification),
    disqualification_reason: clean(body.disqualification_reason),

    lead: {
      name: clean(lead.name),
      phone: clean(lead.phone),
      phone_normalized: clean(lead.phone_normalized)
    },

    answers: {
      experiencia_offroad: clean(answers.experiencia_offroad),
      veiculo: clean(answers.veiculo),
      pets: clean(answers.pets),
      orcamento: clean(answers.orcamento),
      checkin: clean(answers.checkin),
      checkout: clean(answers.checkout)
    },

    statuses: {
      experiencia_offroad: clean(statuses.experiencia_offroad),
      veiculo: clean(statuses.veiculo),
      pets: clean(statuses.pets),
      orcamento: clean(statuses.orcamento)
    },

    tracking: {
      page_url: clean(tracking.page_url),
      page_path: clean(tracking.page_path),
      referrer: clean(tracking.referrer),
      query_string: clean(tracking.query_string),

      utm_source: clean(tracking.utm_source),
      utm_medium: clean(tracking.utm_medium),
      utm_campaign: clean(tracking.utm_campaign),
      utm_content: clean(tracking.utm_content),
      utm_term: clean(tracking.utm_term),
      utm_publico: clean(allParams.utm_publico),

      fbclid: clean(tracking.fbclid),
      gclid: clean(tracking.gclid),
      ttclid: clean(allParams.ttclid),
      _ttp: clean(allParams._ttp),
      _fbp: clean(allParams._fbp),
      _fbc: clean(allParams._fbc),

      ad_id: clean(allParams.ad_id),
      adset_id: clean(allParams.adset_id),
      campaign_id: clean(allParams.campaign_id),
      utm_id: clean(allParams.utm_id),

      all_url_params: allParams
    },

    meta: {
      user_agent: clean(item.json['user-agent']),
      ip: clean(item.json.ip),
      created_at: clean(body.created_at),
      datetime: clean(body.datetime)
    }
  };

  const columns = [
    'lead_counter',
    'datetime',
    'date',
    'email',
    'nome',
    'phone',
    'utm_source',
    'utm_campaign',
    'utm_medium',
    'utm_term',
    'utm_content',
    'utm_publico',
    'utm_urlcompleta',
    'utm_url',
    'utm_referring',
    'utm_pagina',
    'params',
    'fbclid',
    'gclid',
    'ttclid',
    '_ttp',
    '_fbp',
    '_fbc',
    'event',
    'experiencia_offroad',
    'veiculo',
    'pets',
    'orcamento',
    'checkin',
    'checkout',
    'statuses'
  ];

  const values = [
    null,
    datetime,
    date,
    clean(lead.email),
    clean(lead.name),
    normalizePhone(body),

    clean(tracking.utm_source),
    clean(tracking.utm_campaign),
    clean(tracking.utm_medium),
    clean(tracking.utm_term),
    clean(tracking.utm_content),
    clean(allParams.utm_publico),

    clean(tracking.page_url),
    clean(tracking.query_string),
    clean(tracking.referrer),
    clean(tracking.page_path),

    JSON.stringify(params),

    clean(tracking.fbclid),
    clean(tracking.gclid),
    clean(allParams.ttclid),
    clean(allParams._ttp),
    clean(allParams._fbp),
    clean(allParams._fbc),

    clean(body.event),

    clean(answers.experiencia_offroad),
    clean(answers.veiculo),
    clean(answers.pets),
    clean(answers.orcamento),
    clean(answers.checkin),
    clean(answers.checkout),

    JSON.stringify(statuses)
  ];

  const insert = `
INSERT INTO lista_leads (
  ${columns.map(col => `\`${col}\``).join(',\n  ')}
) VALUES (
  ${values.map(value => sql(value)).join(',\n  ')}
);
`.trim();

  return {
    json: {
      sql: insert,

      datetime,
      date,
      nome: clean(lead.name),
      phone: normalizePhone(body),

      event: clean(body.event),
      classification: clean(body.classification),
      disqualification_reason: clean(body.disqualification_reason),

      experiencia_offroad: clean(answers.experiencia_offroad),
      veiculo: clean(answers.veiculo),
      pets: clean(answers.pets),
      orcamento: clean(answers.orcamento),
      checkin: clean(answers.checkin),
      checkout: clean(answers.checkout),

      statuses
    }
  };
});

